1	export type LiveCell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = (x: number, y: number): string => `${x},${y}`;
10	
11	export function nextGeneration(liveCells: LiveCell[]): LiveCell[] {
12	  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
13	  const neighborCounts = new Map<string, number>();
14	  const candidateCells = new Map<string, LiveCell>();
15	
16	  for (const [x, y] of liveCells) {
17	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
18	      const neighbor: LiveCell = [x + dx, y + dy];
19	      const key = cellKey(neighbor[0], neighbor[1]);
20	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
21	      candidateCells.set(key, neighbor);
22	    }
23	  }
24	
25	  const survivesOrBorn = (key: string, count: number): boolean =>
26	    liveSet.has(key) ? count === 2 || count === 3 : count === 3;
27	
28	  return [...neighborCounts.entries()]
29	    .filter(([key, count]) => survivesOrBorn(key, count))
30	    .map(([key]) => candidateCells.get(key)!);
31	}
