type Candidate = { cell: LiveCell; neighborCount: number };

export function nextGeneration(liveCells: LiveCell[]): LiveCell[] {
  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
  const candidates = new Map<string, Candidate>();

  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const cell: LiveCell = [x + dx, y + dy];
      const key = cellKey(cell[0], cell[1]);
      const existing = candidates.get(key);
      candidates.set(key, {
        cell,
        neighborCount: (existing?.neighborCount ?? 0) + 1,
      });
    }
  }

  const survivesOrBorn = ({ cell, neighborCount }: Candidate): boolean =>
    liveSet.has(cellKey(cell[0], cell[1]))
      ? neighborCount === 2 || neighborCount === 3
      : neighborCount === 3;

  return [...candidates.values()]
    .filter(survivesOrBorn)
    .map(({ cell }) => cell);
}

